BEGIN;

DROP TABLE IF EXISTS debugLogsOffline;
CREATE TABLE debugLogsOffline (
    receivedAt STRING,
    uri STRING,
    req STRING,
    res STRING
);

DROP TABLE IF EXISTS areaObjects;
CREATE TABLE areaObjects (
    areaId INTEGER,
    areaObjectId INTEGER,
    areaPointId INTEGER,
    areaObjectBehaviorId INTEGER,
    action STRING,
    PRIMARY KEY (areaId, areaObjectId)
);

DROP TABLE IF EXISTS areaObjectsOriginal;
CREATE TABLE areaObjectsOriginal (
    areaId INTEGER,
    areaObjectId INTEGER,
    areaPointId INTEGER,
    areaObjectBehaviorId INTEGER,
    action STRING,
    PRIMARY KEY (areaId, areaObjectId)
);

DROP TABLE IF EXISTS tipRelease;
CREATE TABLE tipRelease (
    tipId INTEGER,
    areaId INTEGER,
    areaObjectId INTEGER,
    newAreaPointId INTEGER,
    newAreaObjectBehaviorId INTEGER,
    newAction STRING
);

DROP TABLE IF EXISTS areaEnemies;
CREATE TABLE areaEnemies (
    areaId INTEGER,
    areaPointId INTEGER PRIMARY KEY,
    areaEnemyRateSetId INTEGER,
    action STRING
);

DROP TABLE IF EXISTS areaEnemiesOriginal;
CREATE TABLE areaEnemiesOriginal (
    areaId INTEGER,
    areaPointId INTEGER PRIMARY KEY,
    areaEnemyRateSetId INTEGER,
    action STRING
);

DROP TABLE IF EXISTS areaItems;
CREATE TABLE areaItems (
    areaId INTEGER,
    areaItemId INTEGER
);

DROP TABLE IF EXISTS areaBgm;
CREATE TABLE areaBgm (
    areaId INTEGER PRIMARY KEY,
    id INTEGER,
    eventName STRING
);

DROP TABLE IF EXISTS areaBgmOriginal;
CREATE TABLE areaBgmOriginal (
    areaId INTEGER PRIMARY KEY,
    id INTEGER,
    eventName STRING
);

DROP TABLE IF EXISTS userData;
CREATE TABLE userData (
    keyName STRING PRIMARY KEY,
    val STRING
);

DROP TABLE IF EXISTS defaultUserData;
CREATE TABLE defaultUserData (
    keyName STRING PRIMARY KEY,
    val STRING
);

DROP TABLE IF EXISTS gates;
CREATE TABLE gates (
    fromAreaId INTEGER,
    fromPosX REAL,
    fromPosY REAL,
    fromPosZ REAL,
    toAreaId INTEGER,
    toPosX REAL,
    toPosY REAL,
    toPosZ REAL,
    toDirection INTEGER
);

DROP TABLE IF EXISTS characters;
CREATE TABLE characters (
    characterId INTEGER PRIMARY KEY,
    exp INTEGER,
    hp INTEGER,
    attack INTEGER,
    defense INTEGER,
    maxHp INTEGER,
    receivedAt STRING,
    characterOwnershipType INTEGER,
    criticalRate INTEGER,
    criticalDamageRate INTEGER,
    movementSpeed INTEGER,
    damageInflictedRate INTEGER,
    tensionIncreaseRate INTEGER,
    cpRecastRate INTEGER,
    spGaugeIncreaseRate INTEGER,
    attackSpeed INTEGER,
    characterCostumeId INTEGER,
    abnormalityParamSet STRING,
    trainingScoreLevelScore INTEGER,
    trainingScoreRankScore INTEGER,
    actionPointMax INTEGER,
    actionPointRate INTEGER,
    actionPointConsumption INTEGER,
    damageTakenRate INTEGER
);

DROP TABLE IF EXISTS tensionCards;
CREATE TABLE tensionCards (
    tensionCardId INTEGER,
    receivedAt STRING,
    maxLevel INTEGER,
    abilityEfficacies STRING,
    trainingScoreLevelScore INTEGER,
    entityId INTEGER,
    isLocked BOOLEAN
);

DROP TABLE IF EXISTS challengeProgresses;
CREATE TABLE challengeProgresses (
    challengeProgressId INTEGER PRIMARY KEY,
    clearedAt STRING,
    state INTEGER
);

DROP TABLE IF EXISTS nineSequences;
CREATE TABLE nineSequences (
    nineSequenceId INTEGER PRIMARY KEY,
    content STRING
);

DROP TABLE IF EXISTS tips;
CREATE TABLE tips (
    tipId INTEGER,
    releasedAt STRING
);

DROP TABLE IF EXISTS characterCostumes;
CREATE TABLE characterCostumes (
    characterCostumeId INTEGER PRIMARY KEY,
    receivedAt STRING
);

DROP TABLE IF EXISTS totalTasks;
CREATE TABLE totalTasks (
    conditionId INTEGER
);

DROP TABLE IF EXISTS tutorialStates;
CREATE TABLE tutorialStates (
    tutorialStatusKey INTEGER PRIMARY KEY,
    enabled STRING
);

DROP TABLE IF EXISTS shopProducts;
CREATE TABLE shopProducts (
    val STRING
);

DROP TABLE IF EXISTS battleParameters;
CREATE TABLE battleParameters (
    id INTEGER PRIMARY KEY,
    enemies STRING
);

DROP TABLE IF EXISTS formations;
CREATE TABLE formations (
    number INTEGER,
    members STRING,
    cards STRING
);

DROP TABLE IF EXISTS readSequence;
CREATE TABLE readSequence (
    sequenceRequestId INTEGER,
    areaObjects STRING,
    changedResources STRING,
    nineSequenceId INTEGER
);

DROP TABLE IF EXISTS adventureVariables;
CREATE TABLE adventureVariables (
    adventureVariableId INTEGER PRIMARY KEY,
    value INTEGER
);

DROP TABLE IF EXISTS challengeTasks;
CREATE TABLE challengeTasks (
    challengeTaskId INTEGER PRIMARY KEY,
    clearedAt STRING,
    count INTEGER
);

DROP TABLE IF EXISTS battleFinishAreaObjects;
CREATE TABLE battleFinishAreaObjects(
    battleEntryId INTEGER PRIMARY KEY,
    areaObjects STRING
);

DROP TABLE IF EXISTS areaActionSequenceIds;
CREATE TABLE areaActionSequenceIds (
    areaId INTEGER PRIMARY KEY,
    actionSequenceId INTEGER
);

DROP TABLE IF EXISTS defaultAreaActionSequenceIds;
CREATE TABLE defaultAreaActionSequenceIds (
    areaId INTEGER PRIMARY KEY,
    actionSequenceId INTEGER
);

DROP TABLE IF EXISTS readSequenceAreaAction;
CREATE TABLE readSequenceAreaAction (
    sequenceRequestId INTEGER PRIMARY KEY,
    areaId INTEGER,
    actionSequenceId INTEGER
);

DROP TABLE IF EXISTS readSequenceAreaBgm;
CREATE TABLE readSequenceAreaBgm (
    sequenceRequestId INTEGER PRIMARY KEY,
    areaId INTEGER,
    id INTEGER,
    eventName STRING
);

DROP TABLE IF EXISTS areaItemRewards;
CREATE TABLE areaItemRewards (
    areaItemId INTEGER PRIMARY KEY,
    rewards STRING
);

DROP TABLE IF EXISTS questStates;
CREATE TABLE questStates (
    questId INTEGER PRIMARY KEY,
    clearCount INTEGER,
    bestScore INTEGER
);

DROP TABLE IF EXISTS clearedAchievements;
CREATE TABLE clearedAchievements (
    id INTEGER PRIMARY KEY,
    eventFloorNodeId INTEGER
);

DROP TABLE IF EXISTS xbFormations;
CREATE TABLE xbFormations (
    xbId INTEGER PRIMARY KEY,
    content STRING
);

DROP TABLE IF EXISTS xbGameInfos;
CREATE TABLE xbGameInfos (
    xbId INTEGER PRIMARY KEY,
    content STRING
);

DROP TABLE IF EXISTS xbStartGameInfos;
CREATE TABLE xbStartGameInfos (
    xbId INTEGER PRIMARY KEY,
    content STRING
);

DROP TABLE IF EXISTS tensionData;
CREATE TABLE tensionData (
    tensionFluctuationId INTEGER PRIMARY KEY,
    topTeamDelta INTEGER,
    bottomTeamDelta INTEGER,
    topTeamSkitIndex INTEGER,
    bottomTeamSkitIndex INTEGER
);

DROP TABLE IF EXISTS currentXbPlayData;
CREATE TABLE currentXbPlayData (
    xbId INTEGER PRIMARY KEY,
    idx INTEGER
);

DROP TABLE IF EXISTS xbPlayData;
CREATE TABLE xbPlayData (
    idx INTEGER,
    xbId INTEGER,
    nextAtBatGameInfo STRING,
    changedResources STRING,
    currentAtBatGameInfo STRING,
    result STRING,
    PRIMARY KEY (idx, xbId)
);

DROP TABLE IF EXISTS challenges;
CREATE TABLE challenges (
    challengeId INTEGER PRIMARY KEY,
    state INTEGER,
    clearedAt STRING,
    expiresAt STRING
);

DROP TABLE IF EXISTS warpPoints;
CREATE TABLE warpPoints (
    warpPointId INTEGER PRIMARY KEY
);

DROP TABLE IF EXISTS areas;
CREATE TABLE areas (
    areaId INTEGER PRIMARY KEY
);

DROP TABLE IF EXISTS areaGroups;
CREATE TABLE areaGroups (
    areaGroupId INTEGER PRIMARY KEY
);

DROP TABLE IF EXISTS cities;
CREATE TABLE cities (
    cityId INTEGER PRIMARY KEY,
    isGearShopReleased STRING,
    releasedAt STRING
);

DROP TABLE IF EXISTS gachas;
CREATE TABLE gachas (
    gachaId INTEGER PRIMARY KEY,
    gachaCategoryId INTEGER,
    guaranteedCount INTEGER,
    isGuaranteedPickup STRING,
    executionCount INTEGER,
    isSelectable STRING
);

DROP TABLE IF EXISTS gachaButtonStates;
CREATE TABLE gachaButtonStates (
    gachaId INTEGER,
    gachaButtonId INTEGER,
    executionCount INTEGER,
    lastExecutedAt STRING,
    PRIMARY KEY (gachaId, gachaButtonId)
);

DROP TABLE IF EXISTS gachaRates;
CREATE TABLE gachaRates (
    gachaRateId INTEGER PRIMARY KEY,
    gachaRateSetId INTEGER,
    percentRate STRING
);

DROP TABLE IF EXISTS gachaCards;
CREATE TABLE gachaCards (
    cardType INTEGER,
    cardId INTEGER,
    isAttention STRING,
    isSelectable STRING,
    gachaCardId INTEGER,
    gachaRateId INTEGER,
    PRIMARY KEY (gachaRateId, gachaCardId)
);

DROP TABLE IF EXISTS characterPieces;
CREATE TABLE characterPieces (
    characterId INTEGER PRIMARY KEY,
    quantity INTEGER
);

DROP TABLE IF EXISTS mdTensionCard;
CREATE TABLE mdTensionCard (
    tensionCardId INTEGER PRIMARY KEY,
    abilityTensionCardId
);

DROP TABLE IF EXISTS mdAbilityTensionCard;
CREATE TABLE mdAbilityTensionCard (
    abilityTensionCardId INTEGER PRIMARY KEY,
    abilities STRING
);

DROP TABLE IF EXISTS mdAbilityEfficacy;
CREATE TABLE mdAbilityEfficacy (
    abilityEfficacyId INTEGER PRIMARY KEY,
    abilityEfficacyGroupId INTEGER,
    coolTimeMillisecond INTEGER,
    effectCoolTimeMillisecond INTEGER,
    activeTimeMillisecond INTEGER,
    efficacyType INTEGER,
    probability INTEGER,
    activateConditions STRING,
    deactivateConditions STRING,
    sustainConditions STRING,
    targetConditions STRING,
    fValues STRING,
    values_ STRING,
    uiViewPriority INTEGER,
    effectValueSteps STRING,
    targetType INTEGER
);

DROP TABLE IF EXISTS gachaCharacterIds;
CREATE TABLE gachaCharacterIds (
    characterId INTEGER PRIMARY KEY
);

DROP TABLE IF EXISTS characterLimitBreaks;
CREATE TABLE characterLimitBreaks (
    characterId INTEGER PRIMARY KEY,
    limitBreak INTEGER
);

DROP TABLE IF EXISTS tensionCardLimitBreaks;
CREATE TABLE tensionCardLimitBreaks (
    entityId INTEGER PRIMARY KEY,
    limitBreak INTEGER
);

DROP TABLE IF EXISTS mails;
CREATE TABLE mails (
    entityId INTEGER PRIMARY KEY,
    mailType INTEGER,
    subject STRING,
    body STRING,
    sender STRING,
    rewards STRING,
    createdAt STRING,
    endAt STRING,
    opened BOOLEAN
);

DROP TABLE IF EXISTS dungeons;
CREATE TABLE dungeons (
    dungeonId INTEGER PRIMARY KEY,
    isFinished BOOLEAN
);

DROP TABLE IF EXISTS items;
CREATE TABLE items (
    itemId INTEGER PRIMARY KEY,
    quantity INTEGER
);

DROP TABLE IF EXISTS dungeonData;
CREATE TABLE dungeonData (
    id INTEGER PRIMARY KEY,
    name STRING,
    blocks STRING,
    angle INTEGER,
    canHaveMobs INTEGER
);

DROP TABLE IF EXISTS magicOrbs;
CREATE TABLE magicOrbs (
    magicOrbId INTEGER PRIMARY KEY
);

DROP TABLE IF EXISTS areaChangeLocks;
CREATE TABLE areaChangeLocks (
    areaChangeLockId INTEGER PRIMARY KEY
);

DROP TABLE IF EXISTS mdAreaChangeLock;
CREATE TABLE mdAreaChangeLock (
    id INTEGER,
    areaId INTEGER,
    PRIMARY KEY (id, areaId)
);

DROP TABLE IF EXISTS missions;
CREATE TABLE missions (
    missionId INTEGER PRIMARY KEY,
    count INTEGER,
    receivedStepCount INTEGER,
    resetAt STRING,
    clearedAt STRING
);

DROP TABLE IF EXISTS mdFlowerMarkLevel;
CREATE TABLE mdFlowerMarkLevel (
    requiredFlowerMark INTEGER PRIMARY KEY,
    characterMaxLevel INTEGER
);

DROP TABLE IF EXISTS mdBattleEntry;
CREATE TABLE mdBattleEntry (
    id INTEGER PRIMARY KEY,
    enemyLevel INTEGER,
    battleParameterId INTEGER
);

DROP TABLE IF EXISTS mdBattleParameter;
CREATE TABLE mdBattleParameter (
    id INTEGER PRIMARY KEY,
    dropExpFactor REAL
);

DROP TABLE IF EXISTS mdBattleParameterWave;
CREATE TABLE mdBattleParameterWave (
    battleParameterId INTEGER,
    battleWaveId INTEGER
);

DROP TABLE IF EXISTS mdBattleWave;
CREATE TABLE mdBattleWave (
    id INTEGER,
    battleEnemyId INTEGER
);

DROP TABLE IF EXISTS mdEnemyLevel;
CREATE TABLE mdEnemyLevel (
    level INTEGER PRIMARY KEY,
    dropExpFactor REAL,
    atkStatusFactor REAL,
    defStatusFactor REAL,
    hpStatusFactor REAL
);

DROP TABLE IF EXISTS mdEnemy;
CREATE TABLE mdEnemy (
    id INTEGER PRIMARY KEY,
    dropExp INTEGER,
    attack INTEGER,
    defense INTEGER,
    hp INTEGER
);

DROP TABLE IF EXISTS mdBattleEnemy;
CREATE TABLE mdBattleEnemy (
    id INTEGER PRIMARY KEY,
    enemyId INTEGER
);

DROP TABLE IF EXISTS mdCharacterLevel;
CREATE TABLE mdCharacterLevel (
    level INTEGER PRIMARY KEY,
    exp INTEGER,
    statusFactor REAL
);

DROP TABLE IF EXISTS enemyGroupRewards;
CREATE TABLE enemyGroupRewards (
    enemyGroupId INTEGER PRIMARY KEY,
    rewardGroupId INTEGER
);

DROP TABLE IF EXISTS mdItem;
CREATE TABLE mdItem (
    id INTEGER PRIMARY KEY,
    itemType INTEGER,
    maxQuantity INTEGER,
    rarity INTEGER,
    soldGold STRING,
    value INTEGER
);

DROP TABLE IF EXISTS mdRatedRewardSet;
CREATE TABLE mdRatedRewardSet (
    id INTEGER,
    rewardId INTEGER,
    rewardQuantity INTEGER,
    rewardType INTEGER
);

DROP TABLE IF EXISTS mdDungeonDifficulty;
CREATE TABLE mdDungeonDifficulty (
    id INTEGER PRIMARY KEY,
    bonusRatedRewardSetIds STRING,
    bossRatedRewardSetIds STRING,
    enemyLevel INTEGER,
    enemyTrainingScoreId INTEGER,
    goalEnemyRateSetId INTEGER
);

DROP TABLE IF EXISTS mdDungeonEnemyRate;
CREATE TABLE mdDungeonEnemyRate (
    id INTEGER PRIMARY KEY,
    dungeonEnemyRateSetId INTEGER,
    areaEnemyId INTEGER,
    battleEntryId INTEGER
);

DROP TABLE IF EXISTS dungeonEnemies;
CREATE TABLE dungeonEnemies (
    dungeonId INTEGER,
    entityId INTEGER,
    dungeonEnemyRateId INTEGER,
    dungeonPieceId INTEGER,
    dungeonPieceX INTEGER,
    dungeonPieceY INTEGER,
    dungeonPieceIndex INTEGER,
    defeatedAt STRING,
    isBoss BOOL,
    PRIMARY KEY (dungeonId, entityId)
);

DROP TABLE IF EXISTS dungeonStates;
CREATE TABLE dungeonStates (
    dungeonId INTEGER,
    dungeonDifficultyId INTEGER,
    dungeonPieceX INTEGER,
    dungeonPieceY INTEGER,
    dungeonPieceRotate INTEGER,
    dungeonPieceId INTEGER
);

DROP TABLE IF EXISTS mdChallengeTask;
CREATE TABLE mdChallengeTask (
    challengeProgressId INTEGER NOT NULL,
    count INTEGER,
    id INTEGER PRIMARY KEY,
    summaryChallengeId INTEGER,
    targetAreaObjectBehaviorId INTEGER,
    targetAreaPointId INTEGER,
    targetNineSequenceId INTEGER,
    targetRadius INTEGER,
    taskConditionKeyId INTEGER,
    taskConditionType INTEGER,
    totalTaskConditionId INTEGER
);

DROP TABLE IF EXISTS mdAreaObjectBehavior;
CREATE TABLE mdAreaObjectBehavior (
    areaObjectId INTEGER,
    areaPointId INTEGER NOT NULL,
    challengeProgressId INTEGER,
    id INTEGER PRIMARY KEY
);

DROP TABLE IF EXISTS mdAreaObjectBehaviorAction;
CREATE TABLE mdAreaObjectBehaviorAction (
    areaObjectBehaviorId INTEGER PRIMARY KEY,
    areaEnemyId INTEGER,
    areaItemId INTEGER,
    battleEntryId INTEGER,
    dungeonId INTEGER,
    eventLiftId INTEGER,
    fieldBossId INTEGER,
    graffitiArtId INTEGER,
    id INTEGER NOT NULL,
    label_en STRING,
    sequenceId INTEGER,
    sequenceRequestId INTEGER,
    type INTEGER NOT NULL,
    warpPointId INTEGER
);

DROP TABLE IF EXISTS mdAreaObjectBehaviorCondition;
CREATE TABLE mdAreaObjectBehaviorCondition (
    areaObjectBehaviorId INTEGER PRIMARY KEY,
    areaObjectId INTEGER,
    areaObjectState INTEGER,
    id INTEGER,
    type INTEGER NOT NULL
);

DROP TABLE IF EXISTS mdChallengeRoute;
CREATE TABLE mdChallengeRoute (
    currentProgressId INTEGER NOT NULL,
    id INTEGER PRIMARY KEY,
    nextProgressId INTEGER NOT NULL
);

DROP TABLE IF EXISTS hairColors;
CREATE TABLE hairColors (
    charId INTEGER PRIMARY KEY,
    r REAL,
    g REAL,
    b REAL,
    enabled BOOLEAN
);

DROP TABLE IF EXISTS mdSequenceRequest;
CREATE TABLE mdSequenceRequest (
    adventureVariableId INTEGER,
    areaChangeLockId INTEGER,
    areaGroupId INTEGER,
    areaId INTEGER,
    areaObjectId INTEGER,
    areaObjectState INTEGER,
    cityId INTEGER,
    costs STRING,
    eventLiftId INTEGER,
    id INTEGER PRIMARY KEY,
    rewards STRING,
    type INTEGER NOT NULL,
    variableChangeValue INTEGER,
    variableOperator INTEGER
);

DROP TABLE IF EXISTS tutorialTotalTaskConditionIds;
CREATE TABLE tutorialTotalTaskConditionIds (
    id INTEGER PRIMARY KEY
);

